#!/usr/bin/env python3
"""kaiju-knot-driver — build a mixed KAIJU1 knot for a whole model.

Takes: the f16 GGUF (truth), the GGUF-format imatrix (per-tensor H), the
existing IQ2_M knot (base: proven type mix for everything we DON'T
re-encode), and the kaiju-encode-tensor binary. Produces a knot where every
2D attn/ffn weight tensor with an imatrix entry is re-encoded as KAIJU1
from f16 truth; all other tensors (lm_head Q5_K, token_embd IQ3_S, attn_v
Q4_K, norms/biases F32) are copied byte-verbatim from the base knot.

Usage:
  kaiju-knot-driver.py --f16 f16.gguf --imatrix imatrix.gguf \
    --base-knot base.knot --encoder ./kaiju-encode-tensor \
    --out out.knot [--hi-frac 0.10] [--workdir /tmp/kaiju]
"""

import argparse
import json
import os
import struct
import re
import subprocess
import sys

import numpy as np
from gguf import GGUFReader


def read_imatrix_gguf(path):
    """Return {tensor_name: H vector (in_sum2/counts)} from a GGUF imatrix."""
    r = GGUFReader(path)
    sums = {}
    counts = {}
    for t in r.tensors:
        if t.name.endswith(".in_sum2"):
            sums[t.name[: -len(".in_sum2")]] = np.asarray(t.data).reshape(-1).astype(np.float64)
        elif t.name.endswith(".counts"):
            counts[t.name[: -len(".counts")]] = float(np.asarray(t.data).reshape(-1)[0])
    return {
        name: (s / max(counts.get(name, 1.0), 1.0)).astype(np.float32)
        for name, s in sums.items()
    }


def gguf_name_to_knot(name):
    return name.replace(".", "_") + ".bin"


def read_knot(path):
    """Parse a v1 knot: returns (meta dict, payload_offset, file handle)."""
    f = open(path, "rb")
    head = f.read(10)
    assert head[0:4] == b"KNOT", "base must be a v1 knot"
    meta_len = struct.unpack("<I", head[6:10])[0]
    meta = json.loads(f.read(meta_len).decode("utf-8"))
    marker_pos = ((10 + meta_len + 3) // 4) * 4
    f.seek(marker_pos)
    codec_marker = f.read(1)
    body = marker_pos + 1
    return meta, body, f, codec_marker


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--f16", required=True)
    ap.add_argument("--imatrix", required=True)
    ap.add_argument("--base-knot", required=True)
    ap.add_argument("--encoder", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--hi-frac", default="0.10")
    ap.add_argument("--workdir", default="/tmp/kaiju-work")
    ap.add_argument("--writer-re", default=None,
                    help="tensors matching this regex get --writer-hi-frac "
                         "instead of --hi-frac (v2 role-mix: residual-stream "
                         "writers need more side-band; K4 anchor evidence)")
    ap.add_argument("--writer-hi-frac", default="0.30")
    ap.add_argument("--fisher-steps", default="0",
                    help="Fisher-weighted bulk step-search radius K passed to "
                         "the encoder. 0 = legacy unweighted-RMS step (byte-"
                         "identical). K>=1 makes the bulk Leech lane minimize "
                         "the god-formula excess Sum_i H_i(dW_i)^2 per block.")
    ap.add_argument("--include-re", default=None,
                    help="only KAIJU1-encode tensors whose gguf name matches "
                         "this regex; others copy from base (K4 ablations)")
    args = ap.parse_args()
    os.makedirs(args.workdir, exist_ok=True)

    h_map = read_imatrix_gguf(args.imatrix)
    print(f"[driver] imatrix entries: {len(h_map)}", flush=True)

    f16 = GGUFReader(args.f16)
    f16_tensors = {t.name: t for t in f16.tensors}

    base_meta, base_body, base_f, base_marker = read_knot(args.base_knot)
    base_tensors = base_meta["tensors"]

    # Which tensors get KAIJU1: 2D weights with an imatrix H entry whose
    # channel count matches the f16 in-dim. Everything else copies verbatim.
    plan = {}
    for gname, h in h_map.items():
        t = f16_tensors.get(gname)
        if t is None:
            continue
        flat = np.asarray(t.data)
        if flat.dtype != np.float16:
            continue
        n = flat.size
        cols = len(h)
        if n % cols != 0:
            print(f"[driver] skip {gname}: {n} % {cols} != 0", flush=True)
            continue
        kname = gguf_name_to_knot(gname)
        if kname.replace(".bin", "") not in base_tensors and kname not in base_tensors:
            print(f"[driver] skip {gname}: not in base knot TOC", flush=True)
            continue
        if args.include_re and not re.search(args.include_re, gname):
            continue
        plan[gname] = (n // cols, cols)
    print(f"[driver] KAIJU1 plan: {len(plan)} tensors", flush=True)

    # Encode each planned tensor.
    encoded = {}
    telemetry = []
    for i, (gname, (rows, cols)) in enumerate(sorted(plan.items())):
        t = f16_tensors[gname]
        w = np.asarray(t.data).reshape(-1).astype(np.float32)
        wpath = os.path.join(args.workdir, "w.f32")
        hpath = os.path.join(args.workdir, "h.f32")
        opath = os.path.join(args.workdir, "enc.kaiju1")
        w.tofile(wpath)
        h_map[gname].tofile(hpath)
        frac = args.hi_frac
        if args.writer_re and re.search(args.writer_re, gname):
            frac = args.writer_hi_frac
        r = subprocess.run(
            [args.encoder, "--f32", wpath, "--h", hpath, "--rows", str(rows),
             "--cols", str(cols), "--out", opath, "--hi-frac", frac,
             "--fisher-steps", args.fisher_steps],
            capture_output=True, text=True,
        )
        if r.returncode != 0:
            print(f"[driver] ENCODE FAILED {gname}: {r.stderr[-400:]}", flush=True)
            sys.exit(1)
        tele = json.loads(r.stdout.strip().splitlines()[-1])
        tele["tensor"] = gname
        telemetry.append(tele)
        with open(opath, "rb") as ef:
            encoded[gname] = ef.read()
        if i % 20 == 0:
            print(f"[driver] {i+1}/{len(plan)} {gname}: {tele['bpw']:.3f} bpw "
                  f"clamp {tele['clamp']:.4f}", flush=True)

    # Assemble the output knot: same metadata shape as base, tensors dict
    # rebuilt with new offsets; KAIJU1 entries get type "KAIJU1".
    new_meta = {k: v for k, v in base_meta.items() if k != "tensors"}
    new_tensors = {}
    order = list(base_tensors.keys())
    offset = 0
    chunks = []
    knot_key_of = {gguf_name_to_knot(g).replace(".bin", ""): g for g in encoded}
    for name in order:
        info = base_tensors[name]
        gname = knot_key_of.get(name.replace(".bin", ""))
        if gname is not None:
            blob = encoded[gname]
            new_tensors[name] = {"offset": offset, "length": len(blob), "type": "KAIJU1"}
            chunks.append(("mem", blob))
            offset += len(blob)
        else:
            new_tensors[name] = {"offset": offset, "length": info["length"],
                                 "type": info["type"]}
            chunks.append(("base", info["offset"], info["length"]))
            offset += info["length"]
    new_meta["tensors"] = new_tensors
    meta_bytes = json.dumps(new_meta, separators=(",", ":")).encode("utf-8")

    with open(args.out, "wb") as out:
        out.write(b"KNOT")
        out.write(struct.pack("<H", 1))
        out.write(struct.pack("<I", len(meta_bytes)))
        out.write(meta_bytes)
        pad = ((10 + len(meta_bytes) + 3) // 4) * 4 - (10 + len(meta_bytes))
        out.write(b"\x00" * pad)
        out.write(base_marker)  # codec marker copied from base knot
        for chunk in chunks:
            if chunk[0] == "mem":
                out.write(chunk[1])
            else:
                _, off, length = chunk
                base_f.seek(base_body + off)
                remaining = length
                while remaining > 0:
                    buf = base_f.read(min(1 << 24, remaining))
                    out.write(buf)
                    remaining -= len(buf)

    total_bpw = [t["bpw"] for t in telemetry]
    print(f"[driver] wrote {args.out}: {os.path.getsize(args.out)} bytes; "
          f"KAIJU1 tensors {len(encoded)}, mean bpw {sum(total_bpw)/len(total_bpw):.3f}",
          flush=True)
    with open(args.out + ".telemetry.json", "w") as tf:
        json.dump(telemetry, tf, indent=1)


if __name__ == "__main__":
    main()
